import React, { useState } from 'react';
import {
  CContainer, CRow, CCol, CCard, CCardBody, CForm, CFormInput, CButton, CImage
} from '@coreui/react';

const Login = () => {
  const [formValues, setFormValues] = useState({ email: '', password: '' });
  const [errors, setErrors] = useState({});

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormValues({ ...formValues, [name]: value });
    setErrors({ ...errors, [name]: '' });
  };

  const validateForm = () => {
    const newErrors = {};
    if (!formValues.email) newErrors.email = 'Email is required';
    if (!formValues.password) newErrors.password = 'Password is required';
    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    if (validateForm()) {
      // Handle login logic here
      console.log('Logging in with:', formValues);
    }
  };

  return (
    <CContainer fluid className="min-vh-100 d-flex align-items-center justify-content-center bg-purple">
      <CCard className="d-flex flex-row overflow-hidden shadow-lg rounded-4" style={{ maxWidth: '900px', width: '100%' }}>
        <CCol md={6} className="d-none d-md-block">
          <CImage
            src="https://mdbcdn.b-cdn.net/img/Photos/new-templates/bootstrap-login-form/img1.webp"
            alt="login"
            className="w-100 h-100 object-fit-cover"
          />
        </CCol>

        <CCol md={6} className="p-5 d-flex align-items-center">
          <CCardBody className="w-100">
            <div className="text-center mb-4">
              <CImage
                src="/assets/logo.jpeg" // Replace with your local image path
                alt="My College Vision"
                className="img-fluid"
                style={{ maxHeight: '150px' }}
              />
            </div>

            <h4 className="text-center mb-4">Sign into your account</h4>

            <CForm onSubmit={handleSubmit}>
              <div className="mb-3">
                <CFormInput
                  type="email"
                  name="email"
                  label="Email address"
                  value={formValues.email}
                  onChange={handleChange}
                  floatingLabel
                />
                {errors.email && <div className="text-danger small mt-1">{errors.email}</div>}
              </div>

              <div className="mb-4">
                <CFormInput
                  type="password"
                  name="password"
                  label="Password"
                  value={formValues.password}
                  onChange={handleChange}
                  floatingLabel
                />
                {errors.password && <div className="text-danger small mt-1">{errors.password}</div>}
              </div>

              <CButton color="dark" type="submit" className="w-100 mb-3" size="lg">
                LOGIN
              </CButton>

              <div className="text-center">
                <a href="#!" className="text-muted small">Forgot password?</a>
                <p className="mt-3 mb-0">
                  Don't have an account?{' '}
                  <a href="#!" className="fw-bold text-decoration-none text-primary">
                    Register here
                  </a>
                </p>
              </div>
            </CForm>

            <div className="text-center mt-4">
              <a href="#!" className="text-muted small me-3">Terms of use</a>
              <a href="#!" className="text-muted small">Privacy policy</a>
            </div>
          </CCardBody>
        </CCol>
      </CCard>
    </CContainer>
  );
};

export default Login;
